	if headerEnd > 0 && headerEnd < len(body) {
		body = body[headerEnd:]
	}

	if err := json.Unmarshal(body, &resp); err != nil {
		t.Logf("JSON unmarshal failed: %v, raw: %s", err, string(body))
		return nil
	}

	names := make([]string, len(resp.Result.Tools))
	for i, tool := range resp.Result.Tools {
		names[i] = tool.Name
	}
	return names
}

// TestSmokeRunAgainstSelf runs smoke_run against the project's own .smoke.yaml
// as an integration test (skipped if no config found).
func TestSmokeRunAgainstSelf(t *testing.T) {
	configPath := "../../../.smoke.yaml"
	if _, err := os.Stat(configPath); os.IsNotExist(err) {
		t.Skip("no .smoke.yaml found, skipping integration test")
	}

	srv := NewServer()
	handler := srv.Handler("smoke_run")
	if handler == nil {
		t.Fatal("smoke_run handler not registered")
	}

	// The handler should be callable with a config_path argument
	result, err := handler(context.Background(), map[string]interface{}{
		"config_path": configPath,
	})
	if err != nil {
		t.Fatalf("smoke_run handler returned error: %v", err)
	}

	if result == nil {
		t.Fatal("smoke_run handler returned nil result")
	}
}

