package mcp

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"os"
	"testing"
)

// TestNewServerRegistersTools verifies that the MCP server registers all 7 expected tools.
func TestNewServerRegistersTools(t *testing.T) {
	srv := NewServer()
	if srv == nil {
		t.Fatal("NewServer() returned nil")
	}

	// The server should expose 7 tools
	expected := []string{
		"smoke_run",
		"smoke_init",
		"smoke_validate",
		"smoke_list",
		"smoke_discover",
		"smoke_explain",
		"smoke_generate_test",
	}

	// We verify tool registration by starting the server on a pipe,
	// sending a tools/list request, and checking the response.
	gotTools := listToolsOverStdio(t, srv)
	for _, name := range expected {
		found := false
		for _, tool := range gotTools {
			if tool == name {
				found = true
				break
			}
		}
		if !found {
			t.Errorf("expected tool %q not found in registered tools %v", name, gotTools)
		}
	}
}

// toolName is extracted from a tools/list response.
type toolsListResponse struct {
	Result struct {
		Tools []struct {
			Name string `json:"name"`
		} `json:"tools"`
	} `json:"result"`
}

// listToolsOverStdio starts the MCP server on a stdio pipe, sends a tools/list request,
// and returns the names of registered tools.
func listToolsOverStdio(t *testing.T, srv *Server) []string {
	t.Helper()

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Create a pipe: client writes to pw, server reads from pr
	pr, pw := io.Pipe()
	// Server writes to sw, client reads from sr
	sr, sw := net.Pipe()

	// Start server in background
	go func() {
		_ = srv.ServeStdio(ctx, pr, sw)
	}()

	// Send tools/list request
	req := map[string]interface{}{
		"jsonrpc": "2.0",
		"id":      1,
		"method":  "tools/list",
		"params":  map[string]interface{}{},
	}
	reqBytes, _ := json.Marshal(req)
	fmt.Fprintf(pw, "Content-Length: %d\r\n\r\n%s", len(reqBytes), reqBytes)

	// Read response
	buf := make([]byte, 4096)
	n, err := sr.Read(buf)
	if err != nil {
		// If we can't read the response, skip the stdio test and just
		// verify the server has tools via its internal method.
		t.Logf("stdio read failed: %v, falling back to tool count check", err)
		return nil
	}

	var resp toolsListResponse
	// Skip HTTP-style headers
	body := buf[:n]
	headerEnd := 0
	for i := 0; i < len(body)-3; i++ {
		if body[i] == '\r' && body[i+1] == '\n' && body[i+2] == '\r' && body[i+3] == '\n' {
			headerEnd = i + 4
			break
		}
	}
	if headerEnd > 0 && headerEnd < len(body) {
		body = body[headerEnd:]
	}

	if err := json.Unmarshal(body, &resp); err != nil {
		t.Logf("JSON unmarshal failed: %v, raw: %s", err, string(body))
		return nil
	}

	names := make([]string, len(resp.Result.Tools))
	for i, tool := range resp.Result.Tools {
		names[i] = tool.Name
	}
	return names
}

