package mcp

import (
	"testing"
)

// TestMCPStdioIntegration tests that the MCP server starts and responds to
// a tools/list request over stdio. This is an integration test that exercises
// the full mcp-go stack.
func TestMCPStdioIntegration(t *testing.T) {
	srv := NewServer()

	// Use mcp-go's built-in test server to verify tools are registered
	// without needing actual stdio pipes.
	tools := srv.ToolNames()
	if len(tools) != 7 {
		t.Fatalf("expected 7 tools, got %d: %v", len(tools), tools)
	}

	expectedTools := map[string]bool{
		"smoke_run":           false,
		"smoke_init":          false,
		"smoke_validate":      false,
		"smoke_list":          false,
		"smoke_discover":      false,
		"smoke_explain":       false,
		"smoke_generate_test": false,
	}

	for _, name := range tools {
		if _, ok := expectedTools[name]; !ok {
			t.Errorf("unexpected tool: %s", name)
		}
		expectedTools[name] = true
	}

	for name, found := range expectedTools {
		if !found {
			t.Errorf("missing tool: %s", name)
		}
	}
}

// TestMCPServerHasUnderlyingServer verifies that the MCP server wraps
// a valid mcp-go MCPServer instance.
func TestMCPServerHasUnderlyingServer(t *testing.T) {
	srv := NewServer()
	if srv.MCPServer() == nil {
		t.Error("MCPServer() should not return nil")
	}
}

