28		}
29	
30		var configs []SubConfig
31		err := filepath.WalkDir(root, func(path string, d os.DirEntry, err error) error {
32			if err != nil {
33				return nil // skip errors, keep walking
34			}
35			if !d.IsDir() {
36				return nil
37			}
38			name := d.Name()
39	
40			// Skip default dirs
41			if defaultSkipDirs[name] {
42				return filepath.SkipDir
43			}
44			// Skip user-excluded dirs (match relative path)
45			rel, _ := filepath.Rel(root, path)
