				result = append(result, s)
			}
		}
		return result
	default:
		return nil
	}
}

func hasTag(tags []string, filter []string) bool {
	for _, ft := range filter {
		for _, t := range tags {
			if t == ft {
				return true
			}
		}
	}
	return false
}

