// Sanitize truncates output for display in MCP results.
func sanitize(s string, maxLen int) string {
	s = strings.TrimSpace(s)
	if len(s) <= maxLen {
		return s
	}
	return s[:maxLen] + fmt.Sprintf("\n[... truncated, full output: %d bytes]", len(s))
}

