// generateTestYAML creates a YAML snippet for a single test.
func generateTestYAML(name, assertionType string, params map[string]interface{}, tags []string) string {
	var b strings.Builder
	b.WriteString("  - name: ")
	b.WriteString(name)
	b.WriteString("\n")

	if len(tags) > 0 {
		b.WriteString("    tags:\n")
		for _, t := range tags {
			fmt.Fprintf(&b, "      - %s\n", t)
		}
	}

